// Angular use-case: returning [value, error] pairs
function safeParse(json: string): [unknown, null] | [null, Error] {
  try {
    return [JSON.parse(json), null];
  } catch (e) {
    return [null, e as Error];
  }
}

const [value, error] = safeParse('{ "id": 1 }');
