import {
  Component, Input, Output, EventEmitter,
  Signal, signal, computed, inject
} from '@angular/core';

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
}

type SortField = keyof Pick<Product, 'name' | 'price' | 'category'>;
type SortOrder = 'asc' | 'desc';

@Component({ selector: 'app-product-table', template: '' })
export class ProductTableComponent {
  // Typed inputs
  @Input({ required: true }) products!: Product[];
  @Input() sortField: SortField = 'name';
  @Input() sortOrder: SortOrder = 'asc';
  @Input() pageSize: number = 20;

  // Typed output
  @Output() sortChange = new EventEmitter<{ field: SortField; order: SortOrder }>();
  @Output() productSelect = new EventEmitter<Product>();

  // Local computed state
  readonly sorted: Signal<Product[]> = computed(() =>
    [...this.products].sort((a, b) => {
      const dir = this.sortOrder === 'asc' ? 1 : -1;
      return String(a[this.sortField]).localeCompare(String(b[this.sortField])) * dir;
    })
  );

  onSort(field: SortField): void {
    const order: SortOrder =
      this.sortField === field && this.sortOrder === 'asc' ? 'desc' : 'asc';
    this.sortChange.emit({ field, order });
  }
}

interface Product {
  id: number;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
}

// For PATCH endpoints — all fields optional
type ProductPatch = Partial<Product>;

// For API response — omit internal fields
type PublicProduct = Omit<Product, 'id'>;

// For creation — no id yet
type CreateProductDto = Omit<Product, 'id'>;

// Angular component: pick only fields needed for display
type ProductCard = Pick<Product, 'id' | 'name' | 'price' | 'imageUrl'>;

// Record — map of product id to product
type ProductMap = Record<number, Product>;

@Injectable({ providedIn: 'root' })
class ProductCacheService {
  private cache: ProductMap = {};

  get(id: number): Product | undefined {
    return this.cache[id];
  }

  set(product: Product): void {
    this.cache[product.id] = product;
  }

  patch(id: number, changes: Partial<Product>): void {
    if (this.cache[id]) {
      this.cache[id] = { ...this.cache[id], ...changes };
    }
  }
}

