// Building your own mapped types
type Nullable<T> = { [K in keyof T]: T[K] | null };
type Stringified<T> = { [K in keyof T]: string };
type Optional<T> = { [K in keyof T]?: T[K] };

// Conditional modifier — remove readonly
type Mutable<T> = { -readonly [K in keyof T]: T[K] };
// Remove optional
type AllRequired<T> = { [K in keyof T]-?: T[K] };

// Angular use-case: create a "form field" type from a model
type FormFields<T> = {
  [K in keyof T]: {
    value: T[K];
    dirty: boolean;
    errors: string[];
  };
};

type UserForm = FormFields<Pick<User, 'name' | 'email'>>;
