// Basic conditional type
type IsString<T> = T extends string ? true : false;

type A = IsString<string>;  // true
type B = IsString<number>;  // false

// infer — extract a type from a conditional
type UnpackPromise<T> = T extends Promise<infer U> ? U : T;
type UnpackArray<T> = T extends Array<infer U> ? U : T;

type UserPromise = Promise<User>;
type ResolvedUser = UnpackPromise<UserPromise>; // User

// Angular: unwrap an Observable's generic
type UnpackObservable<T> = T extends Observable<infer U> ? U : never;

// Distributive conditional types — applied to each union member
type NonNullable<T> = T extends null | undefined ? never : T;
